qry:select.qry:xquery:
for $r in table('
	select d_empresa from org03_empresas where oi_empresa= {#FILTRO:@oi_empresa}
')/ROWS/ROW

for $r in table('
select NombreDia = case datepart(dw,EZ.f_fecha) when 1 then \'Lunes\' when 2 then \'Martes\' when 3 then \'Miercoles\' when 4 then \'Jueves\' when 5 then \'Viernes\' when 6 then \'Sabado\' when 7 then \'Domingo\' end ,f_Horainicio = EZ.f_Horainicio ,f_Horafin = EZ.f_Horafin ,Tipo_Hora = TH.d_tipohora ,UnidadOrg = UO.d_unidad_org , Posicion = e_posicion FROM TTA03_ESPERANZA EZ , TTA01_TipoHoras TH , ORG02_ESTRUCTURAS EST , ORG01_UNI_ORG UO WHERE EZ.oi_TipoHora = TH.oi_TipoHora and EZ.oi_estructura = EST.oi_estructura and EST.oi_unidad_org = UO.oi_unidad_org and oi_horario ={%=#FILTRO:@oi_horario%} and oi_empresa ={%=#FILTRO:@oi_empresa%}
and oi_calendario ={%=#PARAM_SEL:@oi_calendario%} {%? (#PARAM_SEL:@oi_escuadra!=0) {% and oi_escuadra > {#PARAM_SEL:@oi_escuadra} %} {% %} %} {%? (#FILTRO:@f_des!='') {% and f_fecha > {#FILTRO:@f_des} %} {% %} %} {%? (#FILTRO:@f_has!='') {% and f_fecha < {#FILTRO:@f_has} %} {% %} %}
')/ROWS/ROW
